SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].[Salesperson Code] AS SalespersonCode, [Salesperson_Purchaser].Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Header].[Sell-to Customer No_] AS CustomerCode, [Item].[Season Code], IIf([season code]=[maschere]![principale]![FiltroStagione1],Val([No_ of Pairs]),0) AS PairsS1, IIf([season code]=[maschere]![principale]![FiltroStagione1],Val([Line Amount])-Val([Inv_ Discount Amount]),0) AS SalesValueS1, IIf([season code]=[forms]![principale]![FiltroStagione2],Val([No_ of Pairs]),0) AS PairsS2, IIf([season code]=[forms]![principale]![FiltroStagione2],Val([Line Amount])-Val([Inv_ Discount Amount]),0) AS SalesValueS2, IIf([season code]=[forms]![principale]![FiltroStagione3],Val([No_ of Pairs]),0) AS PairsS3, IIf([season code]=[forms]![principale]![FiltroStagione3],Val([Line Amount])-Val([Inv_ Discount Amount]),0) AS SalesValueS3, [Customer].Name AS CustomerName
FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = [Salesperson_Purchaser].Code) INNER JOIN Item ON [Sales Line].No_ = [Item].No_) INNER JOIN Customer ON [Sales Line].[Sell-to Customer No_] = [Customer].No_
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20) AND (([Sales Line].[Delete Reason])=""));

